module top_module(obf_ina, inb, out, sel);//INPUTS
    input [0:127] obf_ina, inb;
    input sel;

    // OUTPUTS
    output [0:127] out;

    // REGISTERS
    reg [0:127] out;

    always @ (obf_ina or inb or sel)
        begin
        out<= sel ? obf_ina : inb;
        end // always @ (obf_ina or inb or sel)
endmodule
